"use client";

import { Category, Dish, MenuForm, } from "@/data/types/dishMenu";
import { Box, Button, Flex, TextArea, TextField } from "@radix-ui/themes";
import { useFieldArray, UseFormReturn } from "react-hook-form";
import ErrorLabel from "./label/ErrorLabel";

type FormCategoryProps = {
    form: UseFormReturn<MenuForm, any, MenuForm>,
    index: number,
    category: Category
    onRemoveCategory: () => void
}

const CategoryForm = ({ form, index, category, onRemoveCategory }: FormCategoryProps) => {
    const { control, register, formState: { errors } } = form
    const {
        append,
        remove: removeDish,
        fields: dishes } = useFieldArray({
            name: `categories.${index}.dishes`,
            control
        })


    const onAddNewDish = () => {
        const newDish: Dish = {
            id: crypto.randomUUID(),
            name: "",
            price: null,
            description: ""
        }
        append(newDish)
    }

    return <Flex key={category.id} direction="column" gap="2" className="p-5 m-2 border rounded-md" >

        <Box >
            <div className="flex flex-row items-center gap-2 p-2">
                <TextField.Root
                    key={category.id}
                    {...register(`categories.${index}.name`)}
                    size="3"
                    placeholder="Kategoria:"
                    variant="soft"
                    color="green"
                />
                <Button
                    type="button"
                    color="red"
                    onClick={onRemoveCategory}
                    size="1"
                    radius="full">
                    X
                </Button>
            </div>
        </Box>
        {dishes.map((dish, indexDish) => (
            <div key={dish.id} className="flex items-start gap-6">
                <div className="flex-1">
                    <div className="flex items-start gap-4">
                        <Box className="flex-1">
                            <TextField.Root
                                color="jade"
                                variant="classic"
                                placeholder="Wpisz nazwe dania.."
                                {...register(`categories.${index}.dishes.${indexDish}.name`, {
                                    required: true,
                                    minLength: { value: 3, message: "Nazwa dania musi mieć minimum 3 litery" },
                                })}
                            />

                            <ErrorLabel error={errors.categories?.[index]?.dishes?.[indexDish]?.name?.message} id={"minLength"} />
                        </Box>
                        <Box className="w-[200px]">
                            <TextField.Root
                                placeholder="Cena"
                                {...register(`categories.${index}.dishes.${indexDish}.price`, {
                                    required: true,
                                    min: { value: 1, message: "Minimalna cena musi być większa od 0" },
                                })}
                            />

                            <ErrorLabel
                                error={errors.categories?.[index]?.dishes?.[indexDish]?.price?.message}
                                id={"min"} />

                        </Box>
                    </div>
                    <Box className="mt-3">
                        <TextArea
                            placeholder="Krótko opis potrawy..."
                            {...register(`categories.${index}.dishes.${indexDish}.description`, {
                                required: true,
                                minLength: {
                                    value: 10,
                                    message: "Minimum 20 znaków",
                                },
                            })}
                        />

                        <ErrorLabel
                            error={errors.categories?.[index]?.dishes?.[indexDish]?.description?.message}
                            id={"minLength"}
                        />
                    </Box>
                </div>

                {/* PRAWA STRONA: tylko Usuń danie */}
                <div className="shrink-0  pt-1">
                    <Button type="button" size="1" radius="full" onClick={() => removeDish(indexDish)}>
                        X
                    </Button>
                </div>
            </div>
        ))}

        <Box>
            <Button color="gold" m="1" type="button" onClick={onAddNewDish}>
                Dodaj danie
            </Button>
        </Box>


    </Flex>
}

export default CategoryForm